from collections import deque

class AdaptiveSpecDecoder:
    """
    Automatically switches between speculative and standard decoding
    based on a rolling acceptance rate.
    """
    MIN_ALPHA_FOR_SPEC = 0.55   # disable spec decoding below this
    WINDOW = 100                 # rolling window of draft tokens

    def __init__(self, tokenizer, target_model, draft_model, K: int = 4):
        self.tokenizer = tokenizer
        self.target = target_model
        self.draft = draft_model
        self.K = K
        self._recent: deque[int] = deque(maxlen=self.WINDOW)  # 1=accepted, 0=rejected
        self._spec_enabled = True

    @property
    def rolling_alpha(self) -> float:
        if not self._recent:
            return 1.0
        return sum(self._recent) / len(self._recent)

    def generate(self, prompt: str, max_new_tokens: int = 200) -> str:
        if self._spec_enabled and self.rolling_alpha >= self.MIN_ALPHA_FOR_SPEC:
            stats = SpecDecStats()
            result = speculative_generate_tracked(
                self.tokenizer, self.target, self.draft, prompt, stats,
                K=self.K, max_new_tokens=max_new_tokens,
            )
            # Record acceptance outcomes for rolling window
            for _ in range(stats.total_accepted):
                self._recent.append(1)
            rejected = stats.total_draft_tokens - stats.total_accepted
            for _ in range(rejected):
                self._recent.append(0)

            alpha = self.rolling_alpha
            self._spec_enabled = alpha >= self.MIN_ALPHA_FOR_SPEC
            if not self._spec_enabled:
                print(f"SpecDec disabled: rolling alpha={alpha:.3f} < {self.MIN_ALPHA_FOR_SPEC}")
            return result
        else:
            # Standard autoregressive decoding
            return self._standard_decode(prompt, max_new_tokens)

    def _standard_decode(self, prompt: str, max_new_tokens: int) -> str:
        import torch
        ids = self.tokenizer(prompt, return_tensors="pt").input_ids.to(self.target.device)
        out = self.target.generate(ids, max_new_tokens=max_new_tokens, do_sample=True)
        return self.tokenizer.decode(out[0, ids.shape[1]:], skip_special_tokens=True)
